/** @since 5.0 */
export type IANATimeZone = NonNullable<Intl.DateTimeFormatOptions["timeZone"]>;

/** @since 5.0 */
export type SystemTimeZone = "system";

/** @since 5.0 */
export type UnknownTimeZone = "unknown";

/** @since 5.0 */
export type TimeZone = IANATimeZone | SystemTimeZone | UnknownTimeZone;